{
  "title": "Primary 4 Social Studies Exam",
   "description": "Assessment of social studies knowledge for primary 4 students",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice questions",
           "questions": [
               {
                   "text": "What is the main purpose of a community?",
                   "type": "multiple-choice",
                   "points": 2,
                   "difficulty": "easy",
                   "options": [
                       {"text": "To provide entertainment", "isCorrect": false, "letter": "A"},
                       {"text": "To provide basic needs and services", "isCorrect": true, "letter": "B"},
                       {"text": "To build roads", "isCorrect": false, "letter": "C"},
                       {"text": "To create parks", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B",
                   "explanation": "The correct answer is B because a community's main purpose is to provide its members with basic needs and services such as healthcare, education, and security. Options A, C, and D are incorrect because while entertainment, road construction, and park creation can be benefits of a community, they are not its main purpose."
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended questions",
           "questions": [
               {
                   "text": "Describe the importance of cooperation in a community.",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "Cooperation is essential in a community because it allows individuals to work together to achieve common goals. When community members cooperate, they can share resources, expertise, and ideas, leading to better outcomes for everyone. For example, in a neighborhood, cooperation can lead to the organization of community events, the maintenance of public spaces, and the support of local businesses. Cooperation also fosters a sense of belonging and social cohesion, which are critical for the well-being and happiness of community members. Furthermore, cooperation can help to resolve conflicts and address social issues, such as poverty and inequality, by bringing people together to find solutions. In conclusion, cooperation is vital for building a strong, harmonious, and prosperous community.",
                   "gradingCriteria": [
                       "Defines the concept of cooperation (2 marks)",
                       "Explains the benefits of cooperation (3 marks)",
                       "Provides examples of cooperation in a community (2 marks)",
                       "Discusses the impact of cooperation on social issues (2 marks)",
                       "Clear conclusion (1 mark)"
                   ]
               },
               {
                   "text": "What are some ways that individuals can contribute to their community?",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "Individuals can contribute to their community in various ways. One way is by volunteering their time and skills to help those in need, such as at a local food bank or animal shelter. Another way is by participating in community events and activities, such as festivals, parades, and clean-up initiatives. Individuals can also contribute by supporting local businesses and organizations, such as by shopping at local stores or donating to community charities. Additionally, individuals can contribute by taking care of their own property and respecting their neighbors, which helps to maintain a positive and safe community environment. Furthermore, individuals can contribute by speaking up on issues that affect their community, such as advocating for environmental protection or social justice. In conclusion, there are many ways that individuals can make a positive impact in their community.",
                   "gradingCriteria": [
                       "Lists at least three ways to contribute (3 marks)",
                       "Explains the benefits of each contribution (3 marks)",
                       "Provides examples of community events and activities (2 marks)",
                       "Discusses the importance of individual responsibility (2 marks)",
                       "Clear conclusion (1 mark)"
                   ]
               }
           ]
       },
       {
           "name": "C",
           "description": "True / False questions",
           "questions": [
               {
                   "text": "A community is only made up of people who live in the same neighborhood.",
                   "type": "true-false",
                   "points": 1,
                   "difficulty": "easy",
                   "options": [
                       {"text": "True", "isCorrect": false, "letter": "A"},
                       {"text": "False", "isCorrect": true, "letter": "B"}
                   ],
                   "correctAnswer": "False",
                   "explanation": "The statement is false because a community can be made up of people who share common interests, goals, or characteristics, regardless of their geographical location."
               }
           ]
       },
       {
           "name": "D",
           "description": "Short Answer questions",
           "questions": [
               {
                   "text": "What is the role of a local government in a community?",
                   "type": "short-answer",
                   "points": 4,
                   "difficulty": "easy",
                   "correctAnswer": "The local government plays a crucial role in providing essential services such as law enforcement, public transportation, and waste management. It also makes decisions on zoning, taxation, and infrastructure development. Additionally, the local government represents the community's interests and addresses its concerns.",
                   "keyPoints": [
                       "Provides essential services",
                       "Makes decisions on zoning and taxation",
                       "Represents the community's interests"
                   ]
               }
           ]
       },
       {
           "name": "E",
           "description": "Fill in Blank questions",
           "questions": [
               {
                   "text": "A community that values _______ is more likely to have a strong sense of social cohesion.",
                   "type": "fill-in-blank",
                   "points": 1,
                   "difficulty": "easy",
                   "correctAnswer": "diversity",
                   "explanation": "A community that values diversity is more likely to have a strong sense of social cohesion because it recognizes and appreciates the differences among its members.",
                   "acceptableAnswers": [
                       "inclusion",
                       "equality",
                       "tolerance"
                   ]
               }
           ]
       }
   ]
}
